import { useState, useRef, useEffect, useCallback } from "react";

// ── Experiment 2: Module-level declarations ─────────────────────────

const V2_ORBIT_RADIUS  = 200;
const V2_STIFFNESS     = 0.032;
const V2_DAMPING       = 0.88;
const V2_TRIGGER_DELAY = 300;

// ── Experiment 2: Component ─────────────────────────────────────────
function CardDragV2Experiment({ containerScale = 1 }) {
// Re-bind prefixed constants locally
const ORBIT_RADIUS = V2_ORBIT_RADIUS;
const STIFFNESS = V2_STIFFNESS;
const DAMPING = V2_DAMPING;
const TRIGGER_DELAY = V2_TRIGGER_DELAY;

  // Only what React needs to re-render visuals
  const [visual, setVisual] = useState({ x: 0, y: 0, prox: 0, shellProx: 0, cardScale: 1 });
  const [isHovering, setIsHovering] = useState(false);
  const [hoveredOption, setHoveredOption] = useState(null);
  const [resetHovered, setResetHovered] = useState(false);

  // === Card 2 state ===
  const [visual2, setVisual2] = useState({ x: 0, y: 0, prox: 0, shellProx: 0, cardScale: 1 });
  const [isHovering2, setIsHovering2] = useState(false);
  const [hoveredOption2, setHoveredOption2] = useState(null);

  const cardRef = useRef(null);
  const iconRef = useRef(null);
  const outerRef = useRef(null); // direct DOM ref for lag-free rotation
  // Card 2 refs
  const cardRef2 = useRef(null);
  const outerRef2 = useRef(null);
  const rafRef2  = useRef(null);
  const rafRef  = useRef(null);

  // ALL mutable physics state lives here — never goes stale in closures
  const p = useRef({
    x: 0, y: 0, vx: 0, vy: 0,
    prox: 0, shellProx: 0, shellV: 0,
    dragging: false, docked: false,
    inOrbitSince: null, delayFired: false,
    px0: 0, py0: 0, ox: 0, oy: 0,
  });

  const p2 = useRef({
    x: 0, y: 0, vx: 0, vy: 0,
    prox: 0, shellProx: 0, shellV: 0,
    dragging: false, docked: false,
    inOrbitSince: null, delayFired: false,
    px0: 0, py0: 0, ox: 0, oy: 0,
  });

  const calcRaw = useCallback(() => {
    if (!iconRef.current || !cardRef.current) return 0;
    const icon = iconRef.current.getBoundingClientRect();
    const card = cardRef.current.getBoundingClientRect();
    const ix = icon.left + icon.width / 2;
    const iy = icon.top + icon.height / 2;
    const cx = Math.max(card.left, Math.min(ix, card.right));
    const dist = Math.hypot(cx - ix, card.top - iy);
    return Math.max(0, 1 - dist / ORBIT_RADIUS);
  }, []);

  const calcRaw2 = useCallback(() => {
    if (!iconRef.current || !cardRef2.current) return 0;
    const icon = iconRef.current.getBoundingClientRect();
    const card = cardRef2.current.getBoundingClientRect();
    const ix = icon.left + icon.width / 2;
    const iy = icon.top + icon.height / 2;
    const cx = Math.max(card.left, Math.min(ix, card.right));
    const dist = Math.hypot(cx - ix, card.top - iy);
    return Math.max(0, 1 - dist / ORBIT_RADIUS);
  }, []);

  // Single rAF loop — owns everything
  const loop = useCallback(() => {
    const s = p.current;
    const now = performance.now();

    // Spring back to origin — only if NOT docked
    if (!s.dragging && !s.docked) {
      const prevX = s.x;
      const prevY = s.y;
      s.vx = s.vx * DAMPING - s.x * STIFFNESS;
      s.vy = s.vy * DAMPING - s.y * STIFFNESS;
      s.x += s.vx;
      s.y += s.vy;
      if (prevX * s.x < 0) { s.vx *= 0.5; }
      if (prevY * s.y < 0) { s.vy *= 0.5; }
    }

    // When docked and not dragging, smoothly animate prox/shell to 1
    if (s.docked && !s.dragging) {
      s.prox += (1 - s.prox) * 0.18;
      if (s.prox > 0.998) s.prox = 1;
      s.shellV = s.shellV * 0.78 - (s.shellProx - 1) * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
    }

    // Proximity + delay gate — only meaningful while dragging
    if (s.dragging) {
      const rawProx = calcRaw();
      if (rawProx > 0.01) {
        if (!s.inOrbitSince) s.inOrbitSince = now;
        if (!s.delayFired && now - s.inOrbitSince >= TRIGGER_DELAY) s.delayFired = true;
      } else {
        s.inOrbitSince = null;
        s.delayFired = false;
      }

      const targetProx = s.delayFired ? 1 : 0;

      // Smooth prox for colors/opacity
      s.prox += (targetProx - s.prox) * 0.18;
      if (s.prox < 0.002) s.prox = 0;

      // Shell spring
      s.shellV = s.shellV * 0.78 - (s.shellProx - targetProx) * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
    }

    // When not dragging and not docked, decay prox/shell to 0
    if (!s.dragging && !s.docked) {
      s.prox += (0 - s.prox) * 0.25;
      if (s.prox < 0.002) s.prox = 0;
      s.shellV = s.shellV * 0.78 - (s.shellProx - 0) * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
      if (Math.abs(s.shellProx) < 0.002) { s.shellProx = 0; s.shellV = 0; }
    }

    // Card scale
    const rawProx = s.dragging ? calcRaw() : 0;
    const waitProgress = (s.dragging && rawProx > 0.01 && !s.delayFired && s.inOrbitSince)
      ? Math.min(1, (now - s.inOrbitSince) / TRIGGER_DELAY) : 0;
    const cardScale = s.dragging ? 1 - s.prox * 0.04 - waitProgress * 0.01
      : s.docked ? 0.96 : 1;

    setVisual({ x: s.x, y: s.y, prox: s.prox, shellProx: s.shellProx, cardScale, dragging: s.dragging, docked: s.docked });

    // Also update rotation directly on outer div during spring-back
    if (!s.dragging && outerRef.current) {
      const deg = Math.max(-8, Math.min(8, s.x * 0.012));
      outerRef.current.style.transform = `translate(${s.x}px, calc(180px + ${s.y}px)) rotate(${deg}deg)`;
    }

    const still =
      !s.dragging && !s.docked &&
      Math.abs(s.x) < 0.2 && Math.abs(s.y) < 0.2 &&
      Math.abs(s.vx) < 0.1 && Math.abs(s.vy) < 0.1 &&
      s.prox < 0.002 && Math.abs(s.shellProx) < 0.002;

    if (still) {
      s.x = 0; s.y = 0; s.vx = 0; s.vy = 0;
      s.prox = 0; s.shellProx = 0; s.shellV = 0;
      setVisual({ x: 0, y: 0, prox: 0, shellProx: 0, cardScale: 1, docked: false });
    } else {
      rafRef.current = requestAnimationFrame(loop);
    }
  }, [calcRaw]);

  const startLoop = useCallback(() => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    rafRef.current = requestAnimationFrame(loop);
  }, [loop]);

  const onPointerDown = useCallback((e) => {
    e.preventDefault();
    const s = p.current;
    s.dragging = true;
    s.docked = false; // undock on grab
    s.px0 = e.clientX; s.py0 = e.clientY;
    s.ox = s.x; s.oy = s.y;
    s.inOrbitSince = null; s.delayFired = false;
    startLoop();
  }, [startLoop]);

  const onPointerMove = useCallback((e) => {
    const s = p.current;
    if (!s.dragging) return;
    const totalScale = containerScale * 0.8;
    s.x = s.ox + (e.clientX - s.px0) / totalScale;
    s.y = s.oy + (e.clientY - s.py0) / totalScale;
    // Apply rotation directly to DOM — no React state lag
    if (outerRef.current) {
      const deg = Math.max(-8, Math.min(8, s.x * 0.012));
      outerRef.current.style.transform = `translate(${s.x}px, calc(180px + ${s.y}px)) rotate(${deg}deg)`;
    }
  }, [containerScale]);

  const onPointerUp = useCallback(() => {
    const s = p.current;
    if (!s.dragging) return;
    s.dragging = false;

    if (s.delayFired) {
      // Released in orbit zone — DOCK the card
      s.docked = true;
      s.vx = 0; s.vy = 0;
      // Keep prox/shell alive — don't reset
    } else {
      // Released outside orbit — spring back to center
      s.docked = false;
      s.prox = 0; s.shellProx = 0; s.shellV = 0;
      setHoveredOption(null);
    }

    s.inOrbitSince = null;
    s.delayFired = false;
    startLoop();
  }, [startLoop]);

  useEffect(() => {
    window.addEventListener("pointermove", onPointerMove);
    window.addEventListener("pointerup", onPointerUp);
    return () => {
      window.removeEventListener("pointermove", onPointerMove);
      window.removeEventListener("pointerup", onPointerUp);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [onPointerMove, onPointerUp]);

  // ===================== CARD 2 PHYSICS =====================
  const loop2 = useCallback(() => {
    const s = p2.current;
    const now = performance.now();
    if (!s.dragging && !s.docked) {
      const prevX = s.x; const prevY = s.y;
      s.vx = s.vx * DAMPING - s.x * STIFFNESS;
      s.vy = s.vy * DAMPING - s.y * STIFFNESS;
      s.x += s.vx; s.y += s.vy;
      if (prevX * s.x < 0) s.vx *= 0.5;
      if (prevY * s.y < 0) s.vy *= 0.5;
    }
    if (s.docked && !s.dragging) {
      s.prox += (1 - s.prox) * 0.18;
      if (s.prox > 0.998) s.prox = 1;
      s.shellV = s.shellV * 0.78 - (s.shellProx - 1) * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
    }
    if (s.dragging) {
      const rawProx = calcRaw2();
      if (rawProx > 0.01) {
        if (!s.inOrbitSince) s.inOrbitSince = now;
        if (!s.delayFired && now - s.inOrbitSince >= TRIGGER_DELAY) s.delayFired = true;
      } else { s.inOrbitSince = null; s.delayFired = false; }
      const targetProx = s.delayFired ? 1 : 0;
      s.prox += (targetProx - s.prox) * 0.18;
      if (s.prox < 0.002) s.prox = 0;
      s.shellV = s.shellV * 0.78 - (s.shellProx - targetProx) * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
    }
    if (!s.dragging && !s.docked) {
      s.prox += (0 - s.prox) * 0.25;
      if (s.prox < 0.002) s.prox = 0;
      s.shellV = s.shellV * 0.78 - s.shellProx * 0.12;
      s.shellProx = Math.max(0, Math.min(1.08, s.shellProx + s.shellV));
      if (Math.abs(s.shellProx) < 0.002) { s.shellProx = 0; s.shellV = 0; }
    }
    const rawProx = s.dragging ? calcRaw2() : 0;
    const waitProgress = (s.dragging && rawProx > 0.01 && !s.delayFired && s.inOrbitSince)
      ? Math.min(1, (now - s.inOrbitSince) / TRIGGER_DELAY) : 0;
    const cardScale = s.dragging ? 1 - s.prox * 0.04 - waitProgress * 0.01 : s.docked ? 0.96 : 1;
    setVisual2({ x: s.x, y: s.y, prox: s.prox, shellProx: s.shellProx, cardScale, dragging: s.dragging, docked: s.docked });
    if (!s.dragging && outerRef2.current) {
      const deg = Math.max(-8, Math.min(8, s.x * 0.012));
      outerRef2.current.style.transform = `translate(${s.x}px, calc(180px + ${s.y}px)) rotate(${deg}deg)`;
    }
    const still = !s.dragging && !s.docked && Math.abs(s.x) < 0.2 && Math.abs(s.y) < 0.2 && Math.abs(s.vx) < 0.1 && Math.abs(s.vy) < 0.1 && s.prox < 0.002 && Math.abs(s.shellProx) < 0.002;
    if (still) { s.x = 0; s.y = 0; s.vx = 0; s.vy = 0; s.prox = 0; s.shellProx = 0; s.shellV = 0; setVisual2({ x: 0, y: 0, prox: 0, shellProx: 0, cardScale: 1, docked: false }); }
    else { rafRef2.current = requestAnimationFrame(loop2); }
  }, [calcRaw2]);

  const startLoop2 = useCallback(() => {
    if (rafRef2.current) cancelAnimationFrame(rafRef2.current);
    rafRef2.current = requestAnimationFrame(loop2);
  }, [loop2]);

  const onPointerDown2 = useCallback((e) => {
    e.preventDefault();
    const s = p2.current;
    s.dragging = true; s.docked = false;
    s.px0 = e.clientX; s.py0 = e.clientY;
    s.ox = s.x; s.oy = s.y;
    s.inOrbitSince = null; s.delayFired = false;
    startLoop2();
  }, [startLoop2]);

  const onPointerMove2 = useCallback((e) => {
    const s = p2.current;
    if (!s.dragging) return;
    const totalScale = containerScale * 0.8;
    s.x = s.ox + (e.clientX - s.px0) / totalScale;
    s.y = s.oy + (e.clientY - s.py0) / totalScale;
    if (outerRef2.current) {
      const deg = Math.max(-8, Math.min(8, s.x * 0.012));
      outerRef2.current.style.transform = `translate(${s.x}px, calc(180px + ${s.y}px)) rotate(${deg}deg)`;
    }
  }, [containerScale]);

  const onPointerUp2 = useCallback(() => {
    const s = p2.current;
    if (!s.dragging) return;
    s.dragging = false;
    if (s.delayFired) { s.docked = true; s.vx = 0; s.vy = 0; }
    else { s.docked = false; s.prox = 0; s.shellProx = 0; s.shellV = 0; setHoveredOption2(null); }
    s.inOrbitSince = null; s.delayFired = false;
    startLoop2();
  }, [startLoop2]);

  useEffect(() => {
    window.addEventListener("pointermove", onPointerMove2);
    window.addEventListener("pointerup", onPointerUp2);
    return () => {
      window.removeEventListener("pointermove", onPointerMove2);
      window.removeEventListener("pointerup", onPointerUp2);
      if (rafRef2.current) cancelAnimationFrame(rafRef2.current);
    };
  }, [onPointerMove2, onPointerUp2]);
  // ===================== END CARD 2 =====================


  const { x, y, prox, shellProx, cardScale, rotate = 0, dragging = false, docked = false } = visual;
  const revealed = prox > 0.01;
  const pad    = shellProx * 20;
  const padBot = shellProx * 128;
  const optionsOpacity = Math.max(0, (prox - 0.2) / 0.8);

  const { x: x2, y: y2, prox: prox2, shellProx: shellProx2, cardScale: cardScale2, dragging: dragging2 = false, docked: docked2 = false } = visual2;
  const revealed2 = prox2 > 0.01;
  const pad2    = shellProx2 * 20;
  const padBot2 = shellProx2 * 128;
  const optionsOpacity2 = Math.max(0, (prox2 - 0.2) / 0.8);

  // Combined prox for shared elements (icon glow, ambient glow)
  const maxProx = Math.max(prox, prox2);
  const anyRevealed = revealed || revealed2;
  const anyDocked = docked || docked2;

  // Glow color: blend between blue/teal base → green (card1) or orange (card2)
  // Card1 green: #018A4C = rgb(1, 138, 76)
  // Card2 orange: rgb(220, 120, 30)
  const card1Weight = maxProx > 0.001 ? prox / maxProx : 0;
  const card2Weight = maxProx > 0.001 ? prox2 / maxProx : 0;
  // Base color (idle): rgb(120, 90, 220) — blends toward active card's color
  const glowR = Math.round(120 + (1 * card1Weight + 239 * card2Weight - 120) * maxProx);
  const glowG = Math.round(90 + (138 * card1Weight + 116 * card2Weight - 90) * maxProx);
  const glowB = Math.round(220 + (76 * card1Weight + 37 * card2Weight - 220) * maxProx);

  const options = [
    "Explore similar items by Goeritz",
    "Order Goeritz Bench - $999.00",
  ];

  const options2 = [
    "Order replacement via Etsy",
    "Save Item to Library",
  ];

  return (
    <div style={{
      width: "100%", height: "100%",
      background: "#e8eaef",
      display: "flex", alignItems: "center", justifyContent: "center",
      overflow: "hidden",
      fontFamily: "'Inter', -apple-system, sans-serif",
      userSelect: "none", position: "relative",
    }}>

      {/* Ambient glow */}
      <div style={{
        position: "absolute", inset: 0, pointerEvents: "none",
        background: `radial-gradient(ellipse 70% 50% at 50% 0%, rgba(${glowR},${glowG},${glowB},${maxProx * 0.28}) 0%, transparent 80%)`,
      }} />

      {/* Hint */}
      <div style={{
        position: "absolute", bottom: 120, left: "50%",
        transform: "translateX(-50%)",
        color: "#9aa0b4", fontSize: 16, whiteSpace: "nowrap",
        opacity: (anyRevealed || anyDocked) ? 0 : 1,
        transition: "opacity 0.5s ease", pointerEvents: "none",
      }}>
        Drag the card toward the icon ↑
      </div>

      {/* Reset CTA — visible when docked */}
      <button
        onClick={() => {
          const s = p.current;
          s.docked = false; s.dragging = false;
          s.prox = 0; s.shellProx = 0; s.shellV = 0;
          s.inOrbitSince = null; s.delayFired = false;
          setHoveredOption(null);
          startLoop();
          const s2 = p2.current;
          s2.docked = false; s2.dragging = false;
          s2.prox = 0; s2.shellProx = 0; s2.shellV = 0;
          s2.inOrbitSince = null; s2.delayFired = false;
          setHoveredOption2(null);
          startLoop2();
        }}
        onMouseEnter={() => setResetHovered(true)}
        onMouseLeave={() => setResetHovered(false)}
        style={{
          position: "absolute", bottom: 44, left: "50%",
          transform: `translateX(-50%) translateY(${anyDocked ? 0 : 12}px)`,
          opacity: anyDocked ? 1 : 0,
          pointerEvents: anyDocked ? "auto" : "none",
          transition: "opacity 0.35s ease, transform 0.35s ease, background 0.2s ease",
          background: "white",
          border: "none",
          borderRadius: 8,
          padding: "8px 18px",
          fontSize: 13,
          fontWeight: 500,
          color: resetHovered ? "#111" : "#333",
          cursor: "pointer",
          boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          fontFamily: "'Inter', -apple-system, sans-serif",
          display: "flex", alignItems: "center",
        }}
      >
        <span style={{
          display: "inline-flex", alignItems: "center", justifyContent: "center",
          width: resetHovered ? 22 : 0, height: 18, flexShrink: 0,
          overflow: "hidden",
          transition: "width 0.25s cubic-bezier(0.34, 1.56, 0.64, 1)",
        }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" style={{
            transform: resetHovered ? "scale(1)" : "scale(0)",
            opacity: resetHovered ? 1 : 0,
            transition: "transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1), opacity 0.2s ease",
          }}>
            <path d="M12 5V1L7 6L12 11V7C15.31 7 18 9.69 18 13C18 16.31 15.31 19 12 19C8.69 19 6 16.31 6 13H4C4 17.42 7.58 21 12 21C16.42 21 20 17.42 20 13C20 8.58 16.42 5 12 5Z" fill="#111" />
          </svg>
        </span>
        Reset
      </button>

      {/* Intelligence icon — fixed, top center, behind card */}
      <div ref={iconRef} style={{
        position: "absolute", top: 80, left: "50%", marginLeft: -32,
        width: 64, height: 64, background: "white", borderRadius: "50%",
        display: "flex", alignItems: "center", justifyContent: "center",
        zIndex: 5,
        transform: `scale(${1 + maxProx * 0.07})`,
        transformOrigin: "top center",
        boxShadow: anyRevealed
          ? `0 0 0 ${maxProx * 6}px rgba(${glowR},${glowG},${glowB},${maxProx * 0.22}), 0 8px 28px rgba(${glowR},${glowG},${glowB},${maxProx * 0.28})`
          : "0 2px 12px rgba(0,0,0,0.08)",
      }}>
        <svg width={30} height={30} viewBox="0 0 30 30" fill="none">
          <circle cx="15" cy="15" r="15" fill="url(#gi_blue)" />
          <circle cx="15" cy="15" r="15" fill="url(#gi_green)" style={{ opacity: prox }} />
          <circle cx="15" cy="15" r="15" fill="url(#gi_orange)" style={{ opacity: prox2 }} />
          <defs>
            <linearGradient id="gi_blue" x1="0" y1="0" x2="30" y2="30" gradientUnits="userSpaceOnUse">
              <stop stopColor="#9B7FE8" />
              <stop offset="0.45" stopColor="#6FBBE0" />
              <stop offset="1" stopColor="#7DD4C8" />
            </linearGradient>
            <linearGradient id="gi_green" x1="0" y1="0" x2="30" y2="30" gradientUnits="userSpaceOnUse">
              <stop stopColor="#02B866" />
              <stop offset="0.45" stopColor="#018A4C" />
              <stop offset="1" stopColor="#006B3A" />
            </linearGradient>
            <linearGradient id="gi_orange" x1="0" y1="0" x2="30" y2="30" gradientUnits="userSpaceOnUse">
              <stop stopColor="#F8923E" />
              <stop offset="0.45" stopColor="#EF7425" />
              <stop offset="1" stopColor="#D4600A" />
            </linearGradient>
          </defs>
        </svg>
      </div>

      {/*
        KEY FIX: Two separate wrapper divs.
        Outer: handles x/y translation only — NO transition, pure rAF.
        Inner: handles hover scale only — CSS transition OK here (no conflict with position).
      */}
      {/* Cards container */}
      <div style={{ transform: "scale(0.8)", transformOrigin: "center center" }}>
      <div style={{ display: "flex", gap: 140, position: "relative", zIndex: 50 }}>
      <div style={{ width: 360, height: 500, flexShrink: 0, overflow: "visible" }}>
      <div
        ref={outerRef}
        style={{
          position: "relative",
          transform: `translate(${x}px, calc(180px + ${y}px)) rotate(${Math.max(-8, Math.min(8, x * 0.012))}deg)`,
          willChange: "transform",
          zIndex: 50,
          display: "flex", flexDirection: "column", alignItems: "center",
        }}
      >
        {/* Hover + drag scale wrapper — separate from position */}
        <div
          onPointerDown={onPointerDown}
          onMouseEnter={() => setIsHovering(true)}
          onMouseLeave={() => setIsHovering(false)}
          style={{
            display: "flex", flexDirection: "column", alignItems: "center",
            cursor: p.current.dragging ? "grabbing" : "grab",
            touchAction: "none",
            transform: `scale(${p.current.dragging ? Math.max(1.02, cardScale + 0.02) : isHovering ? 1.02 : 1})`,
            // CSS transition ONLY for hover — safe because hover never conflicts with rAF position
            transition: "transform 0.3s ease",
          }}
        >
          {/* Grey shell */}
          <div style={{
            position: "relative",
            padding: `${pad}px ${pad}px ${pad + padBot}px ${pad}px`,
            borderRadius: `${24 + pad * 0.4}px`,
            background: `rgba(243,243,243,${prox})`,
            boxShadow: prox > 0.01
              ? `0 ${4 + prox*6}px ${16 + prox*20}px rgba(0,0,0,${0.05 + prox*0.04})`
              : "none",
          }}>

            {/* Options */}
            <div style={{
              position: "absolute",
              bottom: pad + 8, left: pad, right: pad,
              display: "flex", flexDirection: "column", gap: 4,
              opacity: optionsOpacity,
              pointerEvents: (revealed || docked) ? "auto" : "none",
            }}>
              {options.map((text, i) => (
                <div key={i}
                  onMouseEnter={() => setHoveredOption(i)}
                  onMouseLeave={() => setHoveredOption(null)}
                  style={{
                    display: "flex", alignItems: "center",
                    padding: "12px 18px", cursor: "pointer", borderRadius: 14,
                    background: hoveredOption === i ? "#EAE7E7" : "transparent",
                    transition: "background 0.2s ease",
                  }}
                >
                  <span style={{
                    display: "inline-flex", alignItems: "center", justifyContent: "center",
                    width: hoveredOption === i ? 28 : 0, height: 24, flexShrink: 0,
                    overflow: "hidden",
                    transition: "width 0.25s cubic-bezier(0.34, 1.56, 0.64, 1)",
                  }}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" style={{
                      transform: hoveredOption === i ? "scale(1)" : "scale(0)",
                      opacity: hoveredOption === i ? 1 : 0,
                      transition: "transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1), opacity 0.2s ease",
                    }}>
                      <path d="M12 4L10.59 5.41L16.17 11L4 11L4 13L16.17 13L10.58 18.58L12 20L20 12L12 4Z" fill="#111" />
                    </svg>
                  </span>
                  <span style={{ color: hoveredOption === i ? "#111" : "#565c72", fontSize: 16, letterSpacing: "-0.015em", fontWeight: 500, transition: "color 0.2s" }}>{text}</span>
                </div>
              ))}
            </div>

            {/* White card */}
            <div ref={cardRef} style={{
              width: 360, borderRadius: 24,
              background: "white", overflow: "hidden",
              position: "relative", zIndex: 2, flexShrink: 0,
              boxShadow: prox > 0.01 ? "none"
                : dragging
                ? `0 48px 120px rgba(0,0,0,0.10), 0 24px 60px rgba(0,0,0,0.06), 0 8px 24px rgba(0,0,0,0.04)`
                : `0 4px 16px rgba(0,0,0,0.05)`,
              transition: "box-shadow 0.3s ease",
            }}>
              <div style={{ padding: "20px" }}>
              <div style={{ overflow: "hidden", borderRadius: 18 }}>
              <img src="data:image/jpeg;base64," alt="Ecosystem Utility" style={{ width: "100%", height: 256, objectFit: "cover", display: "block", margin: 0, transition: "transform 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94)", transform: isHovering ? "scale(1.06)" : "scale(1)" }} />
              </div>
              </div>
              <div style={{ padding: "22px 28px 36px", textAlign: "center" }}>
                <h2 style={{ margin: "0 0 10px", fontSize: 22, fontWeight: 400, color: "#111", letterSpacing: "-0.04em", lineHeight: 1.15 }}>
                  Goeritz Bench
                </h2>
                <p style={{ margin: 0, fontSize: 16, color: "#6b7280", lineHeight: 1.55, letterSpacing: "-0.01em" }}>
                  A vibrant green furniture piece inspired<br />by the work of artist Mathias Goeritz
                </p>
              </div>
            </div>

          </div>
        </div>
      </div>
      </div>
      <div style={{ width: 360, height: 500, flexShrink: 0, overflow: "visible" }}>
      <div
        ref={outerRef2}
        style={{
          position: "relative",
          transform: `translate(${x2}px, calc(180px + ${y2}px)) rotate(${Math.max(-8, Math.min(8, x2 * 0.012))}deg)`,
          willChange: "transform",
          zIndex: 50,
          display: "flex", flexDirection: "column", alignItems: "center",
        }}
      >
        {/* Hover + drag scale wrapper — separate from position */}
        <div
          onPointerDown={onPointerDown2}
          onMouseEnter={() => setIsHovering2(true)}
          onMouseLeave={() => setIsHovering2(false)}
          style={{
            display: "flex", flexDirection: "column", alignItems: "center",
            cursor: p2.current.dragging ? "grabbing" : "grab",
            touchAction: "none",
            transform: `scale(${p2.current.dragging ? Math.max(1.02, cardScale2 + 0.02) : isHovering2 ? 1.02 : 1})`,
            // CSS transition ONLY for hover — safe because hover never conflicts with rAF position
            transition: "transform 0.3s ease",
          }}
        >
          {/* Grey shell */}
          <div style={{
            position: "relative",
            padding: `${pad2}px ${pad2}px ${pad2 + padBot2}px ${pad2}px`,
            borderRadius: `${24 + pad2 * 0.4}px`,
            background: `rgba(243,243,243,${prox2})`,
            boxShadow: prox2 > 0.01
              ? `0 ${4 + prox2*6}px ${16 + prox2*20}px rgba(0,0,0,${0.05 + prox2*0.04})`
              : "none",
          }}>

            {/* Options */}
            <div style={{
              position: "absolute",
              bottom: pad2 + 8, left: pad2, right: pad2,
              display: "flex", flexDirection: "column", gap: 4,
              opacity: optionsOpacity2,
              pointerEvents: (revealed2 || docked2) ? "auto" : "none",
            }}>
              {options2.map((text, i) => (
                <div key={i}
                  onMouseEnter={() => setHoveredOption2(i)}
                  onMouseLeave={() => setHoveredOption2(null)}
                  style={{
                    display: "flex", alignItems: "center",
                    padding: "12px 18px", cursor: "pointer", borderRadius: 14,
                    background: hoveredOption2 === i ? "#EAE7E7" : "transparent",
                    transition: "background 0.2s ease",
                  }}
                >
                  <span style={{
                    display: "inline-flex", alignItems: "center", justifyContent: "center",
                    width: hoveredOption2 === i ? 28 : 0, height: 24, flexShrink: 0,
                    overflow: "hidden",
                    transition: "width 0.25s cubic-bezier(0.34, 1.56, 0.64, 1)",
                  }}>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" style={{
                      transform: hoveredOption2 === i ? "scale(1)" : "scale(0)",
                      opacity: hoveredOption2 === i ? 1 : 0,
                      transition: "transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1), opacity 0.2s ease",
                    }}>
                      <path d="M12 4L10.59 5.41L16.17 11L4 11L4 13L16.17 13L10.58 18.58L12 20L20 12L12 4Z" fill="#111" />
                    </svg>
                  </span>
                  <span style={{ color: hoveredOption2 === i ? "#111" : "#565c72", fontSize: 16, letterSpacing: "-0.015em", fontWeight: 500, transition: "color 0.2s" }}>{text}</span>
                </div>
              ))}
            </div>

            {/* White card */}
            <div ref={cardRef2} style={{
              width: 360, borderRadius: 24,
              background: "white", overflow: "hidden",
              position: "relative", zIndex: 2, flexShrink: 0,
              boxShadow: prox2 > 0.01 ? "none"
                : dragging
                ? `0 48px 120px rgba(0,0,0,0.10), 0 24px 60px rgba(0,0,0,0.06), 0 8px 24px rgba(0,0,0,0.04)`
                : `0 4px 16px rgba(0,0,0,0.05)`,
              transition: "box-shadow 0.3s ease",
            }}>
              <div style={{ padding: "20px" }}>
              <div style={{ overflow: "hidden", borderRadius: 18 }}>
              <img src="data:image/jpeg;base64," alt="Ecosystem Utility" style={{ width: "100%", height: 256, objectFit: "cover", display: "block", margin: 0, transition: "transform 0.45s cubic-bezier(0.25, 0.46, 0.45, 0.94)", transform: isHovering2 ? "scale(1.06)" : "scale(1)" }} />
              </div>
              </div>
              <div style={{ padding: "22px 28px 36px", textAlign: "center" }}>
                <h2 style={{ margin: "0 0 10px", fontSize: 22, fontWeight: 400, color: "#111", letterSpacing: "-0.04em", lineHeight: 1.15 }}>
                  HB-3 Table Lamp
                </h2>
                <p style={{ margin: 0, fontSize: 16, color: "#6b7280", lineHeight: 1.55, letterSpacing: "-0.01em" }}>
                  Geometric metal design with a magnetic,<br />freely placeable head.
                </p>
              </div>
            </div>

          </div>
        </div>
      </div>
      </div>
      </div>
      </div>
    </div>
  );
}


